scwin.f_Retrieve = async function () {
  var iCnt = 0;
  // 필수조건 확인
  let ret = await $c.gus.cfValidate($p, [ica_stdYm, acb_version, ed_acctDeptCd, ed_coCd]);
  if (!ret) {
    return;
  }
  if (!(ed_acctCdFrom.getValue() == null || ed_acctCdFrom.getValue() == "")) {
    iCnt = iCnt + 1;
  }
  if (!(ed_acctCdTo.getValue() == null || ed_acctCdTo.getValue() == "")) {
    iCnt = iCnt + 1;
  }
  if (iCnt == 1) {
    await $c.win.alert($p, "계정코드from과 계정코드To를 함께 입력하십시오.");
    return false;
  }

  //ds_aggregation

  //dma_condition.set("acctDept", ed_acctDeptCd.getValue());
  //dma_condition.set("mgntAcctCd", ed_acctCdFrom.getValue());
  //dma_condition.set("mgntQtyAcctCd", ed_acctCdTo.getValue());
  dma_condition.set("lowerDeptIncluYn", cbx_lowerDeptIncluYn.getValue());
  dma_condition.set("distYn", "0");
  dma_condition.set("dpctYn", 0);
  dma_condition.set("exceptionDeptYn", 0);
  dma_condition.set("incluYn", "0");
  ds_aggregation_org.removeAll();
  ds_aggregation.removeAll();

  //submit 처리.
  let searchSubmit = await $c.sbm.execute($p, sbm_search);
  if (searchSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_search_submitdone();
  }
};
scwin.sbm_search_submitdone = async function (e) {
  for (var i = 0; i < ds_aggregation_org.getRowCount(); i++) {
    var totVal01 = Number(ds_aggregation_org.getCellData(i, "thisPlanAmt"));
    var totVal02 = Number(ds_aggregation_org.getCellData(i, "thisRsltsAmt"));
    var totVal03 = Number(ds_aggregation_org.getCellData(i, "bfyyThisAmt"));
    ds_aggregation_org.setCellData(i, "thisSilJeok", totVal01 + totVal02 - totVal03);
  }
  ds_aggregation_org.reform();
  ds_aggregation.setJSON(ds_aggregation_org.getAllJSON());
  ds_aggregation.reform();
  for (var i = 0; i < ds_aggregation.getRowCount(); i++) {
    /*
    ds_aggregation.setIgnoreStatus(true); 
     var totVal01 = Number(ds_aggregation.getCellData(i, "thisPlanAmt"));
    var totVal02 = Number(ds_aggregation.getCellData(i, "thisRsltsAmt"));
    var totVal03 = Number(ds_aggregation.getCellData(i, "bfyyThisAmt"));
    ds_aggregation.setCellData(i, "thisSilJeok", totVal01+totVal02-totVal03);
    
    ds_aggregation.setIgnoreStatus(false); 
    */

    if (totVal03 == 0) {
      gr_aggregation.setCellClass(i, "bfyyThisAmt", "cur-df");
    }
    if (totVal01 == 0) {
      gr_aggregation.setCellClass(i, "thisPlanAmt", "cur-df");
    }
    if (totVal02 == 0) {
      gr_aggregation.setCellClass(i, "thisRsltsAmt", "cur-df");
    }
  }

  //subsum row 갯수

  var nTotalCnt = gr_aggregation.getSubtotalRowList()[0];
  //totalRows.setValue(ds_aggregation.getRowCount()+nTotalCnt);
  totalRows.setValue(ds_aggregation.getRowCount());
  if (ds_aggregation.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    lc_acctDeptCd.setDisabled(true);
  } else {
    lc_acctDeptCd.setDisabled(false);
  }
};

