//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:검색->관리부서 , 2:검색->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function (callObj, select_code, txtCode, txtName, sFlag) {
  var sCmdName = "";
  var code = txtCode.getValue();
  var name = txtName.getValue();
  scwin.udc_objNm = callObj.org_id;
  scwin.udc_select_code = select_code;
  switch (select_code) {
    // 관리부서 PopUp 호출
    case '1':
      var pWhere = ica_stdYm.getValue() + ",,,,,,,,," + ed_coCd.getValue();
      sCmdName = "retrieveAcctDeptCdInfo";
      callObj.setSelectId(sCmdName);
      await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
      //sCmdName,
      code, name, sFlag, null, null, null, null, pWhere, null, null, null, null, null, null, null, null); // 관리부서

      break;

    // 거래처 PopUp 호출
    case '2':
      sCmdName = "retrieveClntList";
      callObj.setSelectId(sCmdName);
      await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
      //sCmdName,
      code, name, sFlag, null, null, null, null, null, null, null, null, null, null, "F", null, null); // 거래처
      break;

    // 계정코드 PopUp 호출
    case '3':
      var param = ",,,,,01";
      sCmdName = "retrieveAcctCdInfo";
      callObj.setSelectId(sCmdName);
      await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
      //sCmdName,
      code, name, sFlag, null, null, null, null, param, null, null, null, null, null, null, null, null); // 계정코드
      break;
  }
};
scwin.udc_AllInOne_callBackFunc = function (rtnList) {
  let codeObj;
  let nameObj;
  if (scwin.udc_objNm == "udc_acctDeptCd") {
    codeObj = ed_acctDeptCd;
    nameObj = ed_acctDeptNm;
  } else if (scwin.udc_objNm == "udc_acctCdFrom") {
    codeObj = ed_acctCdFrom;
    nameObj = ed_acctCdFromNm;
  } else if (scwin.udc_objNm == "udc_acctCdTo") {
    codeObj = ed_acctCdTo;
    nameObj = ed_acctCdToNm;
  }
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      return;
    }
    codeObj.setValue(rtnList[0]); // 코드
    nameObj.setValue(rtnList[1]); // 코드명

    //to-do
    //txtCode.hidVal = rtnList[0];	// 코드

    if (scwin.udc_select_code == '1') {
      dma_condition.set("acctDeptLvl", rtnList[6]);
    }
  } else {
    codeObj.setValue(""); // 코드
    nameObj.setValue(""); // 코드명

    //to-do
    //txtCode.hidVal = "";	// 코드
  }
};

