scwin.f_runExcel = async function () {
  var totCnt = ds_aggregation.getRowCount();
  var sheetTitle = "계정별원가집계표";
  if (totCnt != 0) {
    let cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      //cfGridToExcel(gr_aggregation, sheetTitle, sheetTitle+".xls", 4+8+16);    
      const options = {
        fileName: sheetTitle,
        sheetName: sheetTitle,
        useSubTotal: true
      };
      $c.data.downloadGridViewExcel($p, gr_aggregation, options);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
  }
};

//자회사 회계 시스템 추가에 따른 설정 
scwin.f_setCompanyInfo = async function () {
  //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
  if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
    scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
    scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
  }
  ed_coCd.setValue(scwin.vLoginCoCd);
  scwin.rtnFlag = false;
  await scwin.f_PopUpCompanyInfo('T');
  scwin.interval01 = setInterval(async function () {
    if (scwin.rtnFlag == true) {
      clearInterval(scwin.interval01);
      if (ibx_txtCoClsCd.getValue() > ACConstants.CO_CLS_CD_DONGBU) {
        // 자회사 회계 시스템 
        scwin.isSubCompany = true;
      } else {
        scwin.isSubCompany = false;
      }
      if ('T' == scwin.privAdmin || !scwin.isSubCompany) {
        // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        $c.gus.cfEnableObjects($p, [ed_coCd, ed_coNm, btn_company]);
      } else {
        $c.gus.cfDisableObjects($p, [ed_coCd, ed_coNm, btn_company]);
      }
    }
  }, 30);
};

