scwin.udc_comCode_callBackFunc = async function (rtnList) {
  // SET
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      return;
    }
    ed_coCd.setValue(rtnList[0]); // 코드
    ed_coNm.setValue(rtnList[5]); // 회사명
    ibx_txtCoClsCd.setValue(rtnList[1]); // 회사구분 
  } else {
    ed_coCd.setValue(""); // 코드
    ed_coNm.setValue(""); // 회사명
    ibx_txtCoClsCd.setValue("");
  }
  scwin.rtnFlag = true;
};
